	store  Storer
}

// NewEvaluator is the constructor for an Evaluator.
func NewEvaluator(logger *zap.Logger, store Storer) *Evaluator {
	return &Evaluator{
		logger: logger,
		store:  store,
	}
}

func (e *Evaluator) Evaluate(ctx context.Context, flag *flipt.Flag, r *evaluation.EvaluationRequest) (resp *flipt.EvaluationResponse, err error) {
	// Flag should be of variant type by default. However, for maximum backwards compatibility
	// on this layer, we will check against the integer value of the flag type.
	if int(flag.Type) != 0 || flag.Type != flipt.FlagType_VARIANT_FLAG_TYPE {
		resp = &flipt.EvaluationResponse{}
		resp.Reason = flipt.EvaluationReason_ERROR_EVALUATION_REASON
		return resp, errs.ErrInvalidf("flag type %s invalid", flag.Type)
	}

	var (
		startTime     = time.Now().UTC()
		namespaceAttr = metrics.AttributeNamespace.String(r.NamespaceKey)
		flagAttr      = metrics.AttributeFlag.String(r.FlagKey)
	)

	metrics.EvaluationsTotal.Add(ctx, 1, metric.WithAttributeSet(attribute.NewSet(namespaceAttr, flagAttr)))

	defer func() {
		if err == nil {
			metrics.EvaluationResultsTotal.Add(ctx, 1,
				metric.WithAttributeSet(
					attribute.NewSet(
						namespaceAttr,
						flagAttr,
						metrics.AttributeMatch.Bool(resp.Match),
						metrics.AttributeSegment.String(resp.SegmentKey),
						metrics.AttributeReason.String(resp.Reason.String()),
						metrics.AttributeValue.String(resp.Value),
					),
				),
			)
		} else {
			metrics.EvaluationErrorsTotal.Add(ctx, 1, metric.WithAttributeSet(attribute.NewSet(namespaceAttr, flagAttr)))
		}

		metrics.EvaluationLatency.Record(
			ctx,
			float64(time.Since(startTime).Nanoseconds())/1e6,
			metric.WithAttributeSet(
				attribute.NewSet(
					namespaceAttr,
					flagAttr,
				),
			),
		)
	}()

	resp = &flipt.EvaluationResponse{
		RequestId:      r.RequestId,
		EntityId:       r.EntityId,
		RequestContext: r.Context,
		FlagKey:        r.FlagKey,
		NamespaceKey:   r.NamespaceKey,
	}

	if !flag.Enabled {
		resp.Match = false
		resp.Reason = flipt.EvaluationReason_FLAG_DISABLED_EVALUATION_REASON
		return resp, nil
	}

	rules, err := e.store.GetEvaluationRules(ctx, storage.NewResource(ctx, r.NamespaceKey, r.FlagKey))
	if err != nil {
		resp.Reason = flipt.EvaluationReason_ERROR_EVALUATION_REASON
		return resp, err
	}

	if len(rules) == 0 {
		e.logger.Debug("no rules match")
		return resp, nil
	}

	for _, rule := range rules {
		for _, constraint := range rule.Segments {
			if !e.matchConstraintExpressions(r.Context, constraint) {
				// TODO(evanb) add match debug context
				goto next_rule
			}
		}
		for key, variant := range rule.Segments {
			// TODO(chriscchapman) return all matching distributions
			if dist, ok := variant["default"]; ok {
				resp.Match = true
				resp.SegmentKey = key
				resp.Reason = flipt.EvaluationReason_MATCH_EVALUATION_REASON
				resp.Value = dist.VariantKey
				resp.Attachment = dist.VariantAttachment
				return resp, nil
			}
		}

	next_rule:
	}

	return resp, nil
}

func (e *Evaluator) matchConstraintExpressions(cxt json.RawMessage, cs flipt.Distribution) bool {
	if len(cs) == 0 {
		return false
	}

	var request map[string]interface{}
	if err := json.Unmarshal(cxt, &request); err != nil {
		return false
	}

	for _, c := range cs {
		if !e.matchConstraint(request, c) {
			return false
		}
	}

	return true
}

func (e *Evaluator) matchConstraint(ctx map[string]interface{}, c *flipt.Constraint) bool {
	property, ok := ctx[c.Property]
	if !ok {
		return false
	}

	if c.Operator == "empty" {
		switch v := property.(type) {
		case string:
			return v == ""
		case float64:
			return v == 0
		case bool:
			return !v
		}
		return false
	}

	if c.Operator == "not_empty" {
		switch v := property.(type) {
		case string:
			return v != ""
		case float64:
			return v != 0
		case bool:
			return v
		}
		return false
	}

	switch v := property.(type) {
	case string:
		return e.matchConstraintString(v, c)
	case float64:
		return e.matchConstraintNumber(v, c)
	case bool:
		return e.matchConstraintBoolean(v, c)
	}

	return false
}

func (e *Evaluator) matchConstraintString(value string, c *flipt.Constraint) bool {
	switch c.Operator {
	case "eq":
		return value == c.Value
	case "neq":
		return value != c.Value
	case "prefix":
		return strings.HasPrefix(value, c.Value)
	case "suffix":
		return strings.HasSuffix(value, c.Value)
	case "like":
		return strings.Contains(value, c.Value)
	}
	return false
}

func (e *Evaluator) matchConstraintNumber(value float64, c *flipt.Constraint) bool {
	switch c.Operator {
	case "eq":
		val, err := strconv.ParseFloat(c.Value, 64)
		if err != nil {
			return false
		}
		return value == val
	case "neq":
		val, err := strconv.ParseFloat(c.Value, 64)
		if err != nil {
			return false
		}
		return value != val
	case "lt":
		val, err := strconv.ParseFloat(c.Value, 64)
		if err != nil {
			return false
		}
		return value < val
	case "lte":
		val, err := strconv.ParseFloat(c.Value, 64)
		if err != nil {
			return false
		}
		return value <= val
	case "gt":
		val, err := strconv.ParseFloat(c.Value, 64)
		if err != nil {
			return false
		}
		return value > val
	case "gte":
		val, err := strconv.ParseFloat(c.Value, 64)
		if err != nil {
			return false
		}
		return value >= val
	}
	return false
}

func (e *Evaluator) matchConstraintBoolean(value bool, c *flipt.Constraint) bool {
	switch c.Operator {
	case "true":
		return value
	case "false":
		return !value
	}
	return false
}

func (e *Evaluator) matchConstraints(requestContext json.RawMessage, constraints []storage.EvaluationConstraint, matchType flipt.MatchType, entityId string) (bool, string, error) {
	var request map[string]interface{}
	if err := json.Unmarshal(requestContext, &request); err != nil {
		return false, "", err
	}

	// add entityId to the request context
	request["entityId"] = entityId

	if len(constraints) == 0 {
		return true, "no constraints to match", nil
	}

	matchedConstraints := 0

	for _, constraint := range constraints {
		var op string

		switch constraint.Operator {
		case "IPs":
			op = "in"
		case "not IPs":
			op = "not_in"
		case "contains":
			op = "in"
		case "not contains":
			op = "not_in"
		default:
			op = constraint.Operator
		}

		switch matchType {
		case flipt.MatchType_ALL_MATCH_TYPE:
			if e.matchConstraint(request, constraint, op) {
				matchedConstraints++
			}
		case flipt.MatchType_ANY_MATCH_TYPE:
			if e.matchConstraint(request, constraint, op) {
				return true, fmt.Sprintf("matched constraint %q", constraint.Property), nil
			}
		}
	}

	switch matchType {
	case flipt.MatchType_ALL_MATCH_TYPE:
		if matchedConstraints == len(constraints) {
			var properties []string
			for _, c := range constraints {
				properties = append(properties, c.Property)
			}
			sort.Strings(properties)
			return true, fmt.Sprintf("matched all constraints %q", properties), nil
		}
	}

	return false, "did not match constraints", nil
}

func (e *Evaluator) matchConstraint(ctx map[string]interface{}, constraint storage.EvaluationConstraint, op string) bool {
	value, ok := ctx[constraint.Property]
	if !ok {
		return false
	}

	contextValue := fmt.Sprint(value)

	switch op {
	case "eq":
		return contextValue == constraint.Value
	case "neq":
		return contextValue != constraint.Value
	case "lt":
		v, err := strconv.ParseFloat(contextValue, 64)
		if err != nil {
			return false
		}
		cv, err := strconv.ParseFloat(constraint.Value, 64)
		if err != nil {
			return false
		}
		return v < cv
	case "lte":
		v, err := strconv.ParseFloat(contextValue, 64)
		if err != nil {
			return false
		}
		cv, err := strconv.ParseFloat(constraint.Value, 64)
		if err != nil {
			return false
		}
		return v <= cv
	case "gt":
		v, err := strconv.ParseFloat(contextValue, 64)
		if err != nil {
			return false
		}
		cv, err := strconv.ParseFloat(constraint.Value, 64)
		if err != nil {
			return false
		}
		return v > cv
	case "gte":
		v, err := strconv.ParseFloat(contextValue, 64)
		if err != nil {
			return false
		}
		cv, err := strconv.ParseFloat(constraint.Value, 64)
		if err != nil {
			return false
		}
		return v >= cv
	case "prefix":
		return strings.HasPrefix(contextValue, constraint.Value)
	case "suffix":
		return strings.HasSuffix(contextValue, constraint.Value)
	case "like":
		return strings.Contains(contextValue, constraint.Value)
	case "in":
		return slices.Contains(strings.Split(constraint.Value, ","), contextValue)
	case "not_in":
		return !slices.Contains(strings.Split(constraint.Value, ","), contextValue)
	}

	return false
}

