				&segment.Name,
				&segment.Description,
				&segment.MatchType,
				&createdAt,
				&updatedAt)
	)

	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, errs.ErrNotFoundf("segment %q", req)
		}

		return nil, err
	}

